n2: 	ctx := context.Background()

n3: 	const gracePeriod = 1 * time.Second

n4: 	require, assert := require.New(t), assert.New(t)
n5: 	conn, _ := db.TestSetup(t, "postgres")
n6: 	rw := db.New(conn)
n7: 	wrapper := db.TestWrapper(t)
n8: 	iamRepo := iam.TestRepo(t, conn, wrapper)
n9: 	kms := kms.TestKms(t, conn, wrapper)
n10: 	serversRepo, err := servers.NewRepository(rw, rw, kms)
n11: 	require.NoError(err)
n12: 	sessionRepo, err := session.NewRepository(rw, rw, kms)
n13: 	connectionRepo, err := session.NewConnectionRepository(ctx, rw, rw, kms, session.WithDeadWorkerConnCloseMinGrace(gracePeriod))
n14: 	require.NoError(err)

n15: 	numConns := 12

	// Create two "workers". One will remain untouched while the other "goes
	// away and comes back" (worker 2).
n16: 	worker1 := session.TestWorker(t, conn, wrapper, session.WithServerId("worker1"))
n17: 	worker2 := session.TestWorker(t, conn, wrapper, session.WithServerId("worker2"))

	// Create a few sessions on each, activate, and authorize a connection
n18: 	var connIds []string
n19: 	connIdsByWorker := make(map[string][]string)
n20: 	for i := 0; i < numConns; i++ {
n21: 		serverId := worker1.PrivateId
n22: 		if i%2 == 0 {
n23: 			serverId = worker2.PrivateId
		}
n24: 		sess := session.TestDefaultSession(t, conn, wrapper, iamRepo, session.WithServerId(serverId), session.WithDbOpts(db.WithSkipVetForWrite(true)))
n25: 		sess, _, err = sessionRepo.ActivateSession(ctx, sess.GetPublicId(), sess.Version, serverId, "worker", []byte("foo"))
n26: 		require.NoError(err)
n27: 		c, cs, _, err := session.AuthorizeConnection(ctx, sessionRepo, connectionRepo, sess.GetPublicId(), serverId)
n28: 		require.NoError(err)
n29: 		require.Len(cs, 1)
n30: 		require.Equal(session.StatusAuthorized, cs[0].Status)
n31: 		connIds = append(connIds, c.GetPublicId())
n32: 		if i%2 == 0 {
n33: 			connIdsByWorker[worker2.PrivateId] = append(connIdsByWorker[worker2.PrivateId], c.GetPublicId())
		} else {
n34: 			connIdsByWorker[worker1.PrivateId] = append(connIdsByWorker[worker1.PrivateId], c.GetPublicId())
		}
	}

	// Mark half of the connections connected and leave the others authorized.
	// This is just to ensure we have a spread when we test it out.
n35: 	for i, connId := range connIds {
n36: 		if i%2 == 0 {
n37: 			_, cs, err := connectionRepo.ConnectConnection(ctx, session.ConnectWith{
				ConnectionId:       connId,
				ClientTcpAddress:   "127.0.0.1",
				ClientTcpPort:      22,
				EndpointTcpAddress: "127.0.0.1",
				EndpointTcpPort:    22,
				UserClientIp:       "127.0.0.1",
			})
n38: 			require.NoError(err)
n39: 			require.Len(cs, 2)
n40: 			var foundAuthorized, foundConnected bool
n41: 			for _, status := range cs {
n42: 				if status.Status == session.StatusAuthorized {
n43: 					foundAuthorized = true
				}
n44: 				if status.Status == session.StatusConnected {
n45: 					foundConnected = true
				}
			}
n46: 			require.True(foundAuthorized)
n47: 			require.True(foundConnected)
		}
	}

	// Create the job.
n48: 	job, err := newSessionConnectionCleanupJob(
		func() (*session.ConnectionRepository, error) { return connectionRepo, nil },
		session.DeadWorkerConnCloseMinGrace,
	)
n49: 	job.gracePeriod = gracePeriod // by-pass factory assert so we dont have to wait so long
n50: 	require.NoError(err)

	// sleep the status grace period.
n51: 	time.Sleep(gracePeriod)

	// Push an upsert to the first worker so that its status has been
	// updated.
n52: 	_, rowsUpdated, err := serversRepo.UpsertServer(ctx, worker1, []servers.Option{}...)
n53: 	require.NoError(err)
n54: 	require.Equal(1, rowsUpdated)

	// Run the job.
n55: 	require.NoError(job.Run(ctx))

	// Assert connection state on both workers.
n56: 	assertConnections := func(workerId string, closed bool) {
		connIds, ok := connIdsByWorker[workerId]
		require.True(ok)
		require.Len(connIds, 6)
		for _, connId := range connIds {
			_, states, err := connectionRepo.LookupConnection(ctx, connId, nil)
			require.NoError(err)
			var foundClosed bool
			for _, state := range states {
				if state.Status == session.StatusClosed {
					foundClosed = true
					break
				}
			}
			assert.Equal(closed, foundClosed)
		}
	}

	// Assert that all connections on the second worker are closed
n57: 	assertConnections(worker2.PrivateId, true)
	// Assert that all connections on the first worker are still open
n58: 	assertConnections(worker1.PrivateId, false)
}
"
}

